41	    // Dead cell at 2,1 has only one alive neighbor: (1,0)
42	    const grid = new Set(["1,0"]);
43	    expect(nextGeneration(grid)).toEqual(new Set());
44	  });
45	
46	  it("should handle multiple cells together", () => {
47	    // Multiple cells in different positions evolving simultaneously
48	    const grid = new Set(["0,0", "1,0", "2,0"]);
49	    expect(nextGeneration(grid)).toEqual(new Set(["1,-1", "1,0", "1,1"]));
