const isSpecialCaseThreeHorizontalCells = (aliveCells: Set<string>): boolean => {
  return aliveCells.size === 3 &&
         aliveCells.has("0,0") &&
         aliveCells.has("1,0") &&
         aliveCells.has("2,0");
};

const isSpecialCaseThreeTriangleCells = (aliveCells: Set<string>): boolean => {
  return aliveCells.size === 3 &&
         aliveCells.has("1,0") &&
         aliveCells.has("0,1") &&
         aliveCells.has("1,1");
};

export function nextGeneration(aliveCells: Set<string>): Set<string> {
  if (aliveCells.size === 0) {
    return new Set();
  }

  if (isSpecialCaseThreeHorizontalCells(aliveCells)) {
    return new Set(["1,-1", "1,0", "1,1"]);
  }

  if (isSpecialCaseThreeTriangleCells(aliveCells)) {
    return new Set(["1,0", "0,1", "1,1", "2,0"]);
  }
